import{_ as l,o as e,c as i,ag as s}from"./chunks/framework.f_9xDHrT.js";const m=JSON.parse('{"title":"安装说明","description":"如何安装 MissFisher。","frontmatter":{"title":"安装说明","description":"如何安装 MissFisher。"},"headers":[],"relativePath":"manual/install.md","filePath":"manual/install.md","lastUpdated":1777727305000}'),r={name:"manual/install.md"};function o(t,a,n,h,d,u){return e(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="安装指南" tabindex="-1">安装指南 <a class="header-anchor" href="#安装指南" aria-label="Permalink to &quot;安装指南&quot;">​</a></h1><h2 id="基础依赖" tabindex="-1">基础依赖 <a class="header-anchor" href="#基础依赖" aria-label="Permalink to &quot;基础依赖&quot;">​</a></h2><h2 id="dalamud" tabindex="-1">Dalamud <a class="header-anchor" href="#dalamud" aria-label="Permalink to &quot;Dalamud&quot;">​</a></h2><p>Dalamud 是一个完全免费的 FF14 插件平台。<br> 你需要从 XIVLauncher 启动游戏才能使用 Dalamud。</p><h2 id="xivlauncher-cn-soil" tabindex="-1">XIVLauncher CN (Soil) <a class="header-anchor" href="#xivlauncher-cn-soil" aria-label="Permalink to &quot;XIVLauncher CN (Soil)&quot;">​</a></h2><p>XIVLauncher 是一个第三方 FF14 启动器。XIVLauncher CN (Soil) 是 XIVLauncher CN 的分支版本。</p><p>XIVLauncher CN (Soil) 通常被称为橙月，而原版通常被称为蓝月。</p><details><summary>为什么更建议使用橙月而不是蓝月？</summary><p>橙月相比蓝月，重构并优化了启动器的逻辑、界面和交互，还能更好地支持顺畅的跨大区体验。</p><p>并且，由于 Dalamud 在游戏版本迭代后通常需要重新适配。<br> 蓝月一般会等待 Dalamud 完全适配完毕并发布正式版内核后，才会拉取新内核。</p><p>而橙月在一两天内就会拉取开发版内核，可以更快提供有限但不稳定的插件使用。<br> 当然，您也可以在游戏版本迭代后手动在启动器设置关闭 Dalamud，在观察到 Dalamud 稳定后再启用。</p><p>另外，由于许多中国服社区的主流插件都优先基于橙月的 Dalamud 内核来开发，因此也许也能获得更多兼容性。</p></details><h3 id="使用-xivlauncher-cn-soil-为游戏注入-dalamud" tabindex="-1">使用 XIVLauncher CN (Soil) 为游戏注入 Dalamud <a class="header-anchor" href="#使用-xivlauncher-cn-soil-为游戏注入-dalamud" aria-label="Permalink to &quot;使用 XIVLauncher CN (Soil) 为游戏注入 Dalamud&quot;">​</a></h3><ol><li><a href="https://github.com/AtmoOmen/FFXIVQuickLauncher/releases/latest/download/XIVLauncherCN-win-Portable.zip" target="_blank" rel="noreferrer">下载 XIVLauncher CN (Soil).zip</a>。</li><li>解压并打开 XIVLauncher CN (Soil)。</li><li>设置好游戏目录。</li><li>点击主界面的齿轮图标按钮来打开设置，选择 Dalamud 页签确认 Dalamud 已经启用。</li><li>从主界面登陆游戏，Dalamud 应会在游戏启动后自动注入游戏进程。</li></ol><hr><h1 id="在-dalamud-安装-missfisher" tabindex="-1">在 Dalamud 安装 MissFisher <a class="header-anchor" href="#在-dalamud-安装-missfisher" aria-label="Permalink to &quot;在 Dalamud 安装 MissFisher&quot;">​</a></h1><blockquote><p>以下指引是基于 XIVLauncher CN (Soil) 的，可能与其他版本略有不同，请留意</p></blockquote><h2 id="打开插件安装器" tabindex="-1">打开插件安装器 <a class="header-anchor" href="#打开插件安装器" aria-label="Permalink to &quot;打开插件安装器&quot;">​</a></h2><p><strong>已登陆角色时：</strong></p><ol><li>在游戏中按键盘上的 <code>Esc</code> 直到出现系统选项菜单。</li><li>点击 Dalamud 插件。</li></ol><p><strong>在标题画面时：</strong></p><ol><li>将鼠标移动到游戏标题画面左侧唤出侧栏。</li><li>点击 插件安装器。</li></ol><h2 id="添加仓库链接并安装-missfisher" tabindex="-1">添加仓库链接并安装 MissFisher <a class="header-anchor" href="#添加仓库链接并安装-missfisher" aria-label="Permalink to &quot;添加仓库链接并安装 MissFisher&quot;">​</a></h2><ol><li>点击插件安装器下方的设置按钮</li><li>选择 插件 页签</li><li>在 插件页 选择 第三方插件 页签</li><li>在空的输入框中填入 MissFisher 的仓库链接：</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://raw.githubusercontent.com/BlackCleaverLoli/MissFisher/refs/heads/main/MissFisher.json</span></span></code></pre></div><ol start="5"><li>点击 <code>＋</code> 以添加</li><li>点击 保存按钮（软盘图标）</li><li>在插件安装器，搜索 <code>MissFisher</code></li><li>点击搜索结果中的 <code>MissFisher</code> 部分展开描述</li><li>点击安装按钮并等待完成</li></ol><p>最后，你需要<a href="./auth">完成免费认证</a>才能使用 MissFisher。</p>',23)])])}const p=l(r,[["render",o]]);export{m as __pageData,p as default};
